}

class PaymentSecurity {
  static String generateNonce([int length = 24]) {
    const chars = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
    final rand = Random.secure();
    return List.generate(length, (_) => chars[rand.nextInt(chars.length)]).join();
  }

  static String generateTransactionId() => 'tx_${DateTime.now().microsecondsSinceEpoch}_${generateNonce(8)}';

  static String maskReceipt(String receipt) {
    if (receipt.length <= 12) return '****';
    return '${receipt.substring(0, 6)}****${receipt.substring(receipt.length - 6)}';
  }

  static Map<String, dynamic> sanitizeMetadata(Map<String, dynamic> metadata) {
    final result = <String, dynamic>{};
    for (final entry in metadata.entries) {
      if (_isSensitiveKey(entry.key)) {
        result[entry.key] = '[REDACTED]';
      } else {
        result[entry.key] = entry.value;
      }
    }
    return result;
  }

  static bool _isSensitiveKey(String key) {
    final k = key.toLowerCase();
    return k.contains('card') ||
        k.contains('cvv') ||
        k.contains('cvc') ||
        k.contains('pan') ||
        k.contains('token') ||
        k.contains('secret') ||
        k.contains('password') ||
        k.contains('pin');
  }
}

