class PaymentService {
  final PaymentConfig config;
  final SecureLogger _logger;
  late final InAppPurchaseGateway _iap;
  late final MobileWalletGateway _wallet;
  late final GatewayPaymentProcessor _gateway;
  final StreamController<PaymentTransaction> _transactionsController = StreamController<PaymentTransaction>.broadcast();
  final Map<String, PaymentTransaction> _transactions = {};

  PaymentService._(this.config)
      : _logger = SecureLogger(config.enableLogging) {
    _iap = InAppPurchaseGateway(logger: _logger);
    _wallet = MobileWalletGateway(logger: _logger);
    _gateway = GatewayPaymentProcessor(logger: _logger);
  }

  static Future<PaymentService> create(PaymentConfig config) async {
    final service = PaymentService._(config);
    await service.initialize();
    return service;
  }

  Stream<PaymentTransaction> get transactions => _transactionsController.stream;

  Future<void> initialize() async {
    _logger.log('Initializing payment service');
    await Future.wait([
      _iap.initialize(config),
      _wallet.initialize(config),
      _gateway.initialize(config),
    ]);
    _logger.log('Payment service initialized');
  }

  Future<bool> isProviderSupported(PaymentProvider provider) async {
    switch (provider) {
      case PaymentProvider.inAppPurchase:
        return _iap.isSupported();
      case PaymentProvider.mobileWallet:
        return _wallet.isSupported();
      case PaymentProvider.gateway:
        return _gateway.isSupported();
    }
  }

  Future<PaymentResult> processPayment(PaymentRequest request) async {
    final supported = await isProviderSupported(request.provider);
    if (!supported) {
      return PaymentResult(
        status: PaymentStatus.notSupported,
        transactionId: PaymentSecurity.generateTransactionId(),
        orderId: request.orderId,
        provider: request.provider,
        message: 'Provider not supported on this device',
      );
    }

    final gateway = _gatewayFor(request.provider);
    final result = await gateway.process(request);

    final tx = PaymentTransaction(
      id: result.transactionId,
      orderId: result.orderId,
      provider: result.provider,
      status: result.status,
      amountMinor: request.amountMinor,
      currency: request.currency,
      createdAt: DateTime.now().toUtc(),
      metadata: PaymentSecurity.sanitizeMetadata(request.metadata),
      receipt: result.receipt != null ? PaymentSecurity.maskReceipt(result.receipt!) : null,
    );

    _transactions[tx.id] = tx;
    _transactionsController.add(tx);
    return result;
  }

  Future<PaymentResult> restorePurchases() async {
    final result = await _iap.restorePurchases();
    final tx = PaymentTransaction(
      id: result.transactionId,
      orderId: result.orderId,
      provider: result.provider,
      status: result.status,
      amountMinor: 0,
      currency: 'N/A',
      createdAt: DateTime.now().toUtc(),
      metadata: const {},
      receipt: result.receipt != null ? PaymentSecurity.maskReceipt(result.receipt!) : null,
    );
    _transactions[tx.id] = tx;
    _transactionsController.add(tx);
    return result;
  }

  PaymentTransaction? getTransaction(String id) => _transactions[id];

  List<PaymentTransaction> getAllTransactions() => _transactions.values.toList(growable: false);

  Future<void> dispose() async {
    await Future.wait([
      _iap.dispose(),
      _wallet.dispose(),
      _gateway.dispose(),
    ]);
    await _transactionsController.close();
  }

  PaymentGateway _gatewayFor(PaymentProvider provider) {
    switch (provider) {
      case PaymentProvider.inAppPurchase:
        return _iap;
      case PaymentProvider.mobileWallet:
        return _wallet;
      case PaymentProvider.gateway:
        return _gateway;
    }
  }
}

class PaymentCompliance {
  static const List<String> pciGuidelines = [
    'Do not store raw card data on device',
    'Use tokenization for all payment methods',
    'Ensure TLS for all network traffic',
    'Keep payment processing in native SDKs or compliant gateways',
    'Never log PAN, CVV, or secrets',
    'Use secure enclave / keystore where available',
  ];

  static bool isCompliantConfiguration(PaymentConfig config) {
    return config.merchantId.isNotEmpty;
  }
}

class PaymentModule {
  static Future<PaymentService> launch({
    required String merchantId,
    String? merchantName,
    bool sandbox = true,
    bool enableLogging = false,
    List<String> supportedCountries = const ['US'],
    Map<String, dynamic> gatewayConfig = const {},
    Map<String, dynamic> walletConfig = const {},
    Map<String, dynamic> iapConfig = const {},
  }) async {
    final config = PaymentConfig(
      merchantId: merchantId,
      merchantName: merchantName,
      sandbox: sandbox,
      enableLogging: enableLogging,
      supportedCountries: supportedCountries,
      gatewayConfig: gatewayConfig,
      walletConfig: walletConfig,
      iapConfig: iapConfig,
    );
    if (!PaymentCompliance.isCompliantConfiguration(config)) {
      throw PaymentException('invalid_config', 'Invalid payment configuration');
    }
    return PaymentService.create(config);
  }
}